#include<stdio.h>
int main()
{
	int n, m;
	scanf("%d %d", &n, &m);
	int i, j, k;
	int a[30], b[30];
	for (i = 0; i < m; i++)
	{
		scanf("%d %d", &a[i], &b[i]);
		a[i]--;
		b[i]--;
	}
	int max = 1;
	for (i = 0; i < n; i++)
		max *= 6;
	int used[10][10];
	for (i = 0; i < 10; i++)
		for (j = 0; j < 10; j++)
			used[i][j] = 1;
	int p, q[10];
	int ans = 0, count;
	for (j = 0; j < max; j++)
	{
		p = j;
		for (i = 0; i < n; i++)
		{
			q[i] = p % 6;
			p /= 6;
		}
		for (i = 0; i < 10; i++)
			for (k = i; k < 10; k++)
				used[i][k] = 0;
		count = 0;
		for (i = 0; i < m; i++)
		{
			if (q[a[i]] < q[b[i]])
			{
				if (used[q[a[i]]][q[b[i]]] == 0)
				{
					count++;
					used[q[a[i]]][q[b[i]]] = 1;
				}
			}
			else
			{
				if (used[q[b[i]]][q[a[i]]] == 0)
				{
					count++;
					used[q[b[i]]][q[a[i]]] = 1;
				}
			}
		}
		if (ans < count)ans = count;
	}
	printf("%d\n", ans);
	return 0;
}

