use std::io::Write;

pub struct Scanner {
  buffer: Vec<String>
}

impl Scanner {
  pub fn new() -> Scanner {
    Scanner { buffer: Vec::new() }
  }

  pub fn next<T: std::str::FromStr>(&mut self) -> T {
    loop {
      if let Some(token) = self.buffer.pop() {
          return token.parse().ok().expect("Failed parse");
      }
      let mut input = String::new();
      std::io::stdin().read_line(&mut input).expect("Failed read");
      self.buffer = input.split_whitespace().rev().map(String::from).collect();
    }
  }
}

fn calculate(n: usize, g: &Vec<Vec<usize>>, p: &Vec<usize>) -> i32 {
  let mut found: [[bool; 6]; 6] = [[false; 6]; 6];
  let mut ans: i32 = 0;
  for u in 0..n {
    for &v in g[u].iter() {
      let u = p[u];
      let v = p[v];
      if !found[u][v] {
        found[u][v] = true;
        found[v][u] = true;
        ans += 1;
      }
    }
  }
  return ans;
}

fn gen(d: usize, n: usize, g: &Vec<Vec<usize>>, p: &mut Vec<usize>) -> i32 {
  if d == n {
    return calculate(n, g, p);
  }
  let mut ans: i32 = 0;
  for x in 0..6 {
    p[d] = x;
    ans = std::cmp::max(ans, gen(d + 1, n, g, p));
  }
  return ans;
}

fn main() {
  let stdout = std::io::stdout();
  let mut out = std::io::BufWriter::new(stdout.lock());
  let mut scan = Scanner::new();

  let n: usize = scan.next();
  let m: usize = scan.next();
  let mut g: Vec<Vec<usize>> = vec![vec![]; n];
  for _ in 0..m {
    let u: usize = scan.next();
    let v: usize = scan.next();
    g[u - 1].push(v - 1);
    g[v - 1].push(u - 1);
  }
  let mut p: Vec<usize> = vec![0; n];
  let ans = gen(0, n, &g, &mut p);
  writeln!(out, "{}", ans).unwrap();
}
